database-object.create:
CREATE OR REPLACE FUNCTION fn_count_phones(
	IN personId bigint)
	RETURNS bigint AS
$BODY$
	DECLARE
		phoneCount bigint;
	BEGIN
		SELECT COUNT(*) INTO phoneCount
		FROM phone
		WHERE person_id = personId;
		RETURN phoneCount;
	END;
$BODY$
LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION singleRefCursor()
	RETURNS REFCURSOR AS
$BODY$
	DECLARE
		p_recordset REFCURSOR;
	BEGIN
		OPEN p_recordset FOR SELECT 1;
		RETURN p_recordset;
	END;
$BODY$
LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION fn_is_null(
	IN param varchar(255))
	RETURNS boolean AS
$BODY$
	DECLARE
		result boolean;
	BEGIN
		SELECT param is null INTO result;
		RETURN result;
	END;
$BODY$
LANGUAGE plpgsql;
